var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"검은 범람 발생 20시간 경과","JPN":"黒い氾濫の発生から20時間経過","ENG":"20 hours since the Black Flood onset","TWN":"黑色洪災發生20小時後","DEU":"20 hours since the Black Flood onset","FRA":"20 hours since the Black Flood onset"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"……하늘이 여전히 붉네.","JPN":"……空がまだ赤い。","ENG":"...The sky's still red.","TWN":"……天空依舊是紅的。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그래. 세상의 멸망을 눈앞에 두고 있으니까 말이다.","JPN":"ええ。世界の滅亡が目前に迫っているからね。","ENG":"Yes. Because the end of the world is right in front of us.","TWN":"對啊，畢竟世界的毀滅就在眼前啊。"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"오르카에게 들은 이야기는 도움이 좀 됐니?","JPN":"オルカの話は役に立った？","ENG":"Did what Orca told you help at all?","TWN":"奧爾卡說得那些話有幫助嗎？"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"도움이 되긴 무슨.","JPN":"役に立つもなにも。","ENG":"Help? Not really.","TWN":"哪有什麼幫助。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"그 꼬맹이한테 그런 소리 들으니까 마음만 복잡해지던데.","JPN":"あのガキの話を聞いたら余計複雑な気持ちになったちまったよ。","ENG":"Hearing that from a kid just made my head even messier.","TWN":"聽完那小鬼說得話，我的心裡反而更亂了。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"우리는 프론트 베이로 돌아가는 거야?","JPN":"フロントベイに戻るのか？　あたちたち。","ENG":"Are we heading back to Front Bay?","TWN":"我們會回前灣嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"아니. 우리는 프론트 베이로 돌아가지 않을 거란다.","JPN":"いいえ。私たちはフロントベイには戻らないわ。","ENG":"No. We won't be returning to Front Bay.","TWN":"不，我們不回前灣。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"응?","JPN":"あ？","ENG":"...Huh?","TWN":"嗯？"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그럼, 배에 있는 모두를 모아주겠니?","JPN":"そろそろ、船にいるみんなを集めてくれる？","ENG":"Then gather everyone on the ship, will you?","TWN":"那麼，你能集合所有船上的人嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"지금부터 우리는 욕조의 마개를 뽑아버릴 계획이거든.","JPN":"今から私たちは、浴槽の栓を抜きに行くのよ。","ENG":"We're about to pull the plug out of the bathtub.","TWN":"從現在開始，我們打算拔掉這個浴缸塞子。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"프론트 베이 관리국은 밀려오는 검은 범람에 대응하느라 여념이 없단다.","JPN":"フロントベイ管理局は、迫りくる黒い氾濫の対応で手一杯。","ENG":"The Front Bay Administration is completely tied up handling the surge of the Black Flood.","TWN":"前灣管理局此刻正忙得不可開交，努力應對湧現的黑色洪災。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그래서, 시니어인 잭은 별동대를 창설, 검은 범람의 원인이 되는 크라켄을 우선 토벌하기로 했지.","JPN":"だからシニア・ジャックは別働隊を編成し、黒い氾濫の原因であるクラーケンから討伐することにしたの。","ENG":"So Senior Jack formed a strike team to hunt Kraken, the source of the Black Flood, first.","TWN":"因此Senior傑克創建了分隊，決定優先剿除造成黑色洪災的克拉肯。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그리고 이는… 벨라미, 네가 설명해 주겠니?","JPN":"そしてこれは……ベラミー、説明をお願いできる？","ENG":"And as for the details... Bellamy, would you explain?","TWN":"至於這個計畫……貝拉米，你來說明吧？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"최고 관리자님께서 지시하신 선로전환기의 가동과 관련이 있어요.","JPN":"最高管理者様が指示した線路転換器の稼働と関連しています。","ENG":"It relates to activating the Track Switcher ordered by the Supreme Administrator.","TWN":"它與最高管理者指示的線路轉換器啟動有關。"},"stage":{"bg":"OMEN_LOTUS_02","slots":{"L":null,"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"전달해 주신 정보에 의하면, 우리는 마왕의 현실 강림을 저지하기 위해 움직일 겁니다.","JPN":"お伝えいただいた情報によると、私たちは魔王の現実降臨の阻止に向けて、動くことになるようです。","ENG":"According to the information we received, we're moving to stop the Demon Lord's descent into reality.","TWN":"根據收到的情報，我們行動的目的是阻止魔王降臨現實。"},"stage":{"bg":"OMEN_LOTUS_02","slots":{"L":null,"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"크라켄은 지금껏 심해의 대균열을 틀어막는 마개 역할을 하고 있었단다.","JPN":"クラーケンは今まで、深海の大亀裂を塞ぐ栓のような役割をしていたわ。","ENG":"Kraken has been acting as a stopper, plugging the Grand Dimension Crevice deep in the sea.","TWN":"克拉肯一直充當著深海大峽谷的蓋子角色。"},"stage":{"bg":"OMEN_LOTUS_02","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"프론트 베이가 검은 범람에 의해 피해를 입으면서도 완전 토벌을 우려하는 이유가 그것 때문이지.","JPN":"フロントベイが黒い氾濫によって被害を受けながらも、完全討伐を躊躇する理由はそのせい。","ENG":"That's why Front Bay hesitated to fully eliminate it, even with the damage from the Black Flood.","TWN":"這就是為什麼前灣因黑色洪災受損，又擔心完全圍剿的緣故。"},"stage":{"bg":"OMEN_LOTUS_02","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"다행히 크라켄은 지난번 검은 범람 때의 상처가 아직 회복되지 않았다는 것을 알아냈단다.","JPN":"幸い、クラーケンは前回の黒い氾濫の時の傷がまだ回復しきっていないことを確認したわ。","ENG":"Fortunately, we discovered Kraken still hasn't recovered from the wounds it suffered last time.","TWN":"幸運的是，我們發現克拉肯在上次黑色洪災中受的傷尚未痊癒。"},"stage":{"bg":"OMEN_LOTUS_02","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"우리는 먼저 프론트 베이가 선로전환기를 가동할 시간을 벌 거야.","JPN":"私たちは、フロントベイが線路転換器を稼働するまでの時間を稼ぐ。","ENG":"Our goal is to buy Front Bay time to activate the Track Switcher.","TWN":"我們要先爭取時間，讓前灣有機會啟動線路轉換器。"},"stage":{"bg":"OMEN_LOTUS_02","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"본래는 마하 섬을 확보한 뒤, 그곳에 선로전환기를 설치하는 것이 가장 인상적이라고는 하나…….","JPN":"本来ならマッハ島を確保し、そこに線路転換器を設置するのが理想的だったんだけど……","ENG":"Originally, securing Macha Island and installing the Track Switcher there would've been ideal...","TWN":"原本確保瑪查島後，在島上安置轉換器會更理想……"},"stage":{"bg":"OMEN_LOTUS_02","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"아무래도 관리국은 직접 함선을 이끌고 와 선로전환기를 가동할 계획인 것 같구나.","JPN":"どうやら管理局は、直接艦船を持ってきて、線路転換器を稼働する計画のようね。","ENG":"But it seems the Administration plans to bring a ship themselves and activate it directly.","TWN":"但看來管理局打算親自帶艦船過來操作轉換器。"},"stage":{"bg":"OMEN_LOTUS_02","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"탈리네 아줌마도 알고 있겠지만, 도시 상황은 좋지 않아.","JPN":"タリーのお母さんも知ってると思うけど、都市の状況は芳しくない。","ENG":"Tallie's mom probably knows already, but things in the city are bad.","TWN":"塔莉家的阿姨應該也清楚，城市的情況並不樂觀。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"격벽은 이미 뚫린 지 오래고, 시민들은 관리국 본부로 대피한 상황이라고.","JPN":"隔壁はとっくに突破されてるし、市民は管理局本部に避難してる。","ENG":"The bulwark has long since been breached, and citizens have evacuated to the Administration HQ.","TWN":"隔離牆早已被突破，市民們全都撤往管理局本部。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"듣자 하니, 프론트 베이의 공인 카운터는 10년 전부터 요양 중이라 들었는데…….","JPN":"聞いた話だと、フロントベイの公認カウンターは10年前から療養中らしいけど……","ENG":"And from what I've heard, Front Bay's Official Counter has been bedridden for ten years...","TWN":"聽說前灣區公認制裁者從10年前就一直在療養……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"이런 상황에서 우리가 그런 도박 수를 강행해야 할 이유가 뭐지?","JPN":"こんな状況で、あたしたちがそんな賭けに出なきゃならない理由って何？","ENG":"So why are we even taking a gamble like this?","TWN":"在這種情況下，我們為什麼要冒這種險呢？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"좋은 질문이구나, 에이버리의 아이야.","JPN":"いいことを聞いてくれたわ、エイバリーの子。","ENG":"A good question, child of Avery.","TWN":"好問題，艾維利的孩子。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};